    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "employee_id" "uuid" NOT NULL,
    "period_month" integer NOT NULL,
    "period_year" integer NOT NULL,
    "basic_salary" numeric(14,2) DEFAULT 0 NOT NULL,
    "allowances" numeric(14,2) DEFAULT 0 NOT NULL,
    "deductions" numeric(14,2) DEFAULT 0 NOT NULL,
    "net_salary" numeric(14,2) DEFAULT 0 NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "earnings" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "deductions_detail" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "gross_earnings" numeric(14,2) DEFAULT 0 NOT NULL,
    "total_deductions" numeric(14,2) DEFAULT 0 NOT NULL,
    "employer_pf" numeric(14,2) DEFAULT 0 NOT NULL,
    "employer_esi" numeric(14,2) DEFAULT 0 NOT NULL,
    "working_days" numeric(5,1),
    "paid_days" numeric(5,1),
    "lop_days" numeric(5,1) DEFAULT 0 NOT NULL,
    "approved_by" "uuid",
    "paid_on" "date",
    "payment_method" "text",
    "payment_reference" "text",
    CONSTRAINT "payroll_records_period_month_check" CHECK ((("period_month" >= 1) AND ("period_month" <= 12))),
    CONSTRAINT "payroll_records_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'approved'::"text", 'paid'::"text"])))
);

ALTER TABLE ONLY "public"."payroll_records" FORCE ROW LEVEL SECURITY;


--
-- Name: payrolls; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE "public"."payrolls" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "employee_id" "uuid" NOT NULL,
    "payroll_month" character varying(7) NOT NULL,
    "basic_salary" numeric(14,2) DEFAULT 0 NOT NULL,
    "salary_type" character varying(20) DEFAULT 'monthly'::character varying,
    "total_working_days" integer DEFAULT 26,
    "present_days" numeric(5,2) DEFAULT 0,
    "absent_days" numeric(5,2) DEFAULT 0,
    "late_days" integer DEFAULT 0,
    "early_leave_days" integer DEFAULT 0,
    "total_worked_hours" numeric(6,2) DEFAULT 0,
    "required_working_hours" numeric(6,2) DEFAULT 0,
    "paid_leave_days" numeric(5,2) DEFAULT 0,
    "sick_leave_days" numeric(5,2) DEFAULT 0,
    "casual_leave_days" numeric(5,2) DEFAULT 0,
    "unpaid_leave_days" numeric(5,2) DEFAULT 0,
    "half_day_leave" numeric(5,2) DEFAULT 0,
    "remaining_leave_balance" numeric(5,2) DEFAULT 0,
    "lop_days" numeric(5,2) DEFAULT 0,
    "per_day_salary" numeric(14,2) DEFAULT 0,
    "lop_deduction" numeric(14,2) DEFAULT 0,
    "lop_reason" "text",
    "normal_ot_hours" numeric(6,2) DEFAULT 0,
    "night_ot_hours" numeric(6,2) DEFAULT 0,
    "holiday_ot_hours" numeric(6,2) DEFAULT 0,
    "per_hour_salary" numeric(14,2) DEFAULT 0,
    "normal_ot_multiplier" numeric(4,2) DEFAULT 1.25,
    "night_ot_multiplier" numeric(4,2) DEFAULT 1.50,
    "holiday_ot_multiplier" numeric(4,2) DEFAULT 2.00,
    "total_ot_amount" numeric(14,2) DEFAULT 0,
    "total_allowances" numeric(14,2) DEFAULT 0,
    "total_deductions" numeric(14,2) DEFAULT 0,
    "gross_salary" numeric(14,2) DEFAULT 0,
    "net_salary" numeric(14,2) DEFAULT 0,
    "payroll_status" character varying(30) DEFAULT 'draft'::character varying,
    "payment_status" character varying(20) DEFAULT 'unpaid'::character varying,
    "payment_date" "date",
    "payment_method" character varying(30),
    "transaction_id" character varying(100),
    "payment_notes" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


